# Mock Trusted Issuer Keys (for testing)
# In a real scenario, these would be resolved via DID or pre-loaded in OPA data
PRIVATE_KEY = {
    "kty": "oct",
    "k": "secret" # Simple symmetric key for testing
}
ISSUER_DID = "did:web:issuer.example.com"

def _generate_vc(agent_did, permissions, constraints, valid_from=None, valid_until=None):
    """Generate a signed JWT VC with embedded authorization policy."""
    now = datetime.utcnow()
    if not valid_from:
        valid_from = now
    if not valid_until:
        valid_until = now + timedelta(hours=1)

    payload = {
        "iss": ISSUER_DID,
        "sub": agent_did,
        "nbf": int(valid_from.timestamp()),
        "exp": int(valid_until.timestamp()),
        "vc": {
            "@context": ["https://www.w3.org/2018/credentials/v1"],
            "type": ["VerifiableCredential", "AgentAuthorizationCredential"],
            "credentialSubject": {
                "id": agent_did,
                "permissions": permissions
            },
            "termsOfUse": [
                {
                    "type": "PolicyConstraint",
                    "constraints": constraints
                }
            ]
        }
    }
    return jwt.encode(payload, PRIVATE_KEY["k"], algorithm="HS256")

def _wait_for_opa(url: str, timeout: float = 10.0) -> bool:
    deadline = time.monotonic() + timeout
    while time.monotonic() < deadline:
        try:
            r = httpx.get(f"{url}/health", timeout=1.0)
            if r.status_code == 200:
                return True
        except Exception:
            pass
        time.sleep(0.2)
    return False

def _start_opa(bundle_path: str, port: int) -> subprocess.Popen:
    return subprocess.Popen(
        [
            OPA_BIN, "run", "--server",
            f"--addr=127.0.0.1:{port}",
            "--log-level=error",
            "--bundle", bundle_path,
        ],
        stdout=subprocess.PIPE,
        stderr=subprocess.PIPE,
    )

def _make_bundle_tar(policies: dict, data: dict = None) -> bytes:
    buf = io.BytesIO()
    with tarfile.open(fileobj=buf, mode="w:gz") as tf:
        if data:
            data_json = json.dumps(data).encode()
            info = tarfile.TarInfo(name="data/data.json")
            info.size = len(data_json)
            tf.addfile(info, io.BytesIO(data_json))

        for name, content in policies.items():
            encoded = content.encode()
            info = tarfile.TarInfo(name=name)
            info.size = len(encoded)
            tf.addfile(info, io.BytesIO(encoded))
    return buf.getvalue()

