    def test_happy_path_valid_vc(self, opa_server):
        """Valid VC with matching constraints should be allowed."""
        agent_did = "did:ethr:0x1234"
        vc = _generate_vc(
            agent_did=agent_did,
            permissions=["damage_assessment:read"],
            constraints=[
                {"type": "EnumeratedList", "field": "resource.id", "values": ["claim-999"]},
                {"type": "NumericLimit", "field": "context.claim_value", "operator": "<=", "value": 5000}
            ]
        )

        request = {
            "input": {
                "schema_version": "v1",
                "namespace": "insurance",
                "subject": {"id": agent_did, "type": "agent"},
                "action": {"name": "damage_assessment:read"},
                "resource": {"id": "claim-999", "type": "other"},
                "context": {
                    "env": "prod", 
                    "timestamp": int(time.time() * 1000),
                    "claim_value": 4200
                },
                "credentials": [vc]
            }
        }

        r = httpx.post(f"{opa_server}/v1/data/agentops/authz", json=request)
        body = r.json()
        assert body.get("result", {}).get("allow") is True, f"Expected allow, got deny: {body}"

